import React, { useEffect, useState } from "react";
import {
  Box, Card, CardContent, Typography, Button, Snackbar, Alert
} from "@mui/material";
import { MapContainer, TileLayer, Marker, Polyline, Popup } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import axios from "axios";
import { useAuth } from "../../contexts/AuthContext";
import { io } from "socket.io-client";
import L from "leaflet";

const socket = io("http://localhost:5000");

export default function RiderDashboard() {
  const [pendingRides, setPendingRides] = useState([]);
  const [activeRideLocations, setActiveRideLocations] = useState({});
  const [snackbar, setSnackbar] = useState({ open: false, message: "", type: "success" });
  const { auth } = useAuth();

  // Fetch pending rides
  const fetchPendingRides = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/rides/pending", {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      setPendingRides(res.data.rides || []);
    } catch {
      setSnackbar({ open: true, message: "Failed to fetch pending rides", type: "error" });
    }
  };

  // Accept ride
  const acceptRide = async (id) => {
    try {
      await axios.post(`http://localhost:5000/api/rides/${id}/accept`, {}, {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      fetchPendingRides();
    } catch {
      setSnackbar({ open: true, message: "Failed to accept ride", type: "error" });
    }
  };

  // Reject ride
  const rejectRide = async (id) => {
    try {
      await axios.post(`http://localhost:5000/api/rides/${id}/reject`, {}, {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      fetchPendingRides();
    } catch {
      setSnackbar({ open: true, message: "Failed to reject ride", type: "error" });
    }
  };

  useEffect(() => {
    fetchPendingRides();

    socket.on("rideRequest", (ride) => {
      setPendingRides((prev) => [...prev, ride]);
    });

    socket.on("riderLocationUpdate", ({ rideId, coords }) => {
      setActiveRideLocations((prev) => ({ ...prev, [rideId]: coords }));
    });

    return () => {
      socket.off("rideRequest");
      socket.off("riderLocationUpdate");
    };
  }, []);

  const riderIcon = new L.DivIcon({
    className: "live-rider-dot",
    html: `<div style="width:16px;height:16px;background:red;border-radius:50%;border:2px solid white;"></div>`,
  });

  return (
    <Box p={4}>
      <Typography variant="h4" gutterBottom>Pending Ride Requests</Typography>

      <Box sx={{ display: "grid", gridTemplateColumns: "1fr 2fr", gap: 2 }}>
        {/* Left panel */}
        <Box>
          {pendingRides.length === 0 ? (
            <Typography>No rides</Typography>
          ) : (
            pendingRides.map((ride) => (
              <Card key={ride._id} sx={{ borderRadius: 2, mb: 2 }}>
                <CardContent>
                  <Typography>Pickup: {ride.pickup}</Typography>
                  <Typography>Drop: {ride.drop}</Typography>
                  <Typography>Status: {ride.status}</Typography>
                  <Box mt={2} display="flex" gap={2}>
                    <Button variant="contained" color="success" onClick={() => acceptRide(ride._id)}>Accept</Button>
                    <Button variant="contained" color="error" onClick={() => rejectRide(ride._id)}>Reject</Button>
                  </Box>
                </CardContent>
              </Card>
            ))
          )}
        </Box>

        {/* Right panel: Map */}
        <Box>
          <MapContainer center={[17.385044, 78.486671]} zoom={12} style={{ height: "600px", width: "100%" }}>
            <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
            {pendingRides.map((ride) => (
              <>
                {ride.pickupCoords && (
                  <Marker key={`pickup-${ride._id}`} position={[ride.pickupCoords.lat, ride.pickupCoords.lng]}>
                    <Popup>Pickup: {ride.pickup}</Popup>
                  </Marker>
                )}
                {ride.dropCoords && (
                  <Marker key={`drop-${ride._id}`} position={[ride.dropCoords.lat, ride.dropCoords.lng]}>
                    <Popup>Drop: {ride.drop}</Popup>
                  </Marker>
                )}
              </>
            ))}
            {Object.entries(activeRideLocations).map(([rideId, coords]) => (
              <Marker key={`live-${rideId}`} position={[coords.lat, coords.lng]} icon={riderIcon}>
                <Popup>Live Rider Location</Popup>
              </Marker>
            ))}
          </MapContainer>
        </Box>
      </Box>

      <Snackbar open={snackbar.open} autoHideDuration={3000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}>
        <Alert severity={snackbar.type}>{snackbar.message}</Alert>
      </Snackbar>
    </Box>
  );
}
